import{_ as s,o as i,c as a,a2 as t}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Persistence Schema","description":"","frontmatter":{},"headers":[],"relativePath":"reference/persistence-schema.md","filePath":"reference/persistence-schema.md","lastUpdated":null}'),o={name:"reference/persistence-schema.md"};function l(n,e,r,d,c,p){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="persistence-schema" tabindex="-1">Persistence Schema <a class="header-anchor" href="#persistence-schema" aria-label="Permalink to &quot;Persistence Schema&quot;">​</a></h1><p>Autofac uses EF Core migrations in <code>src/Autofac.Infrastructure</code> with the default PostgreSQL schema <code>autofac</code>.</p><p>The model stores timestamps as ISO-8601 strings in text columns and uses <code>jsonb</code> for list-valued fields.</p><h2 id="core-tables" tabindex="-1">Core tables <a class="header-anchor" href="#core-tables" aria-label="Permalink to &quot;Core tables&quot;">​</a></h2><h3 id="workflows" tabindex="-1"><code>workflows</code> <a class="header-anchor" href="#workflows" aria-label="Permalink to &quot;`workflows`&quot;">​</a></h3><p>Stores workflow definitions, status, metadata, tags, and BPMN XML.</p><p>Important fields:</p><ul><li><code>Id</code></li><li><code>Name</code></li><li><code>Version</code></li><li><code>Status</code></li><li><code>Owner</code></li><li><code>ValidationState</code></li><li><code>Tags</code></li><li><code>BpmnXml</code></li></ul><h3 id="workflow-runs" tabindex="-1"><code>workflow_runs</code> <a class="header-anchor" href="#workflow-runs" aria-label="Permalink to &quot;`workflow_runs`&quot;">​</a></h3><p>Stores one workflow execution.</p><p>Important fields:</p><ul><li><code>Id</code></li><li><code>WorkflowId</code></li><li><code>WorkflowName</code></li><li><code>WorkflowVersion</code></li><li><code>Status</code></li><li><code>RiskLevel</code></li><li><code>CurrentStep</code></li><li><code>RequestedBy</code></li><li><code>StartedAt</code></li><li><code>CompletedAt</code></li><li><code>PendingApprovals</code></li><li><code>Tags</code></li></ul><h3 id="workflow-run-steps" tabindex="-1"><code>workflow_run_steps</code> <a class="header-anchor" href="#workflow-run-steps" aria-label="Permalink to &quot;`workflow_run_steps`&quot;">​</a></h3><p>Stores step-level execution state, output, and policy decision details.</p><p>Important fields:</p><ul><li><code>RunId</code></li><li><code>Name</code></li><li><code>Type</code></li><li><code>Status</code></li><li><code>AgentName</code></li><li><code>Output</code></li><li><code>PolicyDecision_*</code></li></ul><h3 id="workflow-events" tabindex="-1"><code>workflow_events</code> <a class="header-anchor" href="#workflow-events" aria-label="Permalink to &quot;`workflow_events`&quot;">​</a></h3><p>Stores run-scoped event messages and timestamps.</p><h3 id="workflow-run-context" tabindex="-1"><code>workflow_run_context</code> <a class="header-anchor" href="#workflow-run-context" aria-label="Permalink to &quot;`workflow_run_context`&quot;">​</a></h3><p>Stores run-scoped key/value context such as:</p><ul><li><code>input.body</code></li><li><code>input.title</code></li><li><code>output.WriteRequirements</code></li></ul><p>Writes upsert by <code>(RunId, Key)</code>.</p><h3 id="approval-requests" tabindex="-1"><code>approval_requests</code> <a class="header-anchor" href="#approval-requests" aria-label="Permalink to &quot;`approval_requests`&quot;">​</a></h3><p>Stores approval task state, risk information, decision comment, decision timestamp, and approver identity.</p><h3 id="agent-interactions" tabindex="-1"><code>agent_interactions</code> <a class="header-anchor" href="#agent-interactions" aria-label="Permalink to &quot;`agent_interactions`&quot;">​</a></h3><p>Stores run-scoped agent communications:</p><ul><li>coordination-bus posts</li><li>questions</li><li>choices</li><li>notifications</li><li><code>agent.request</code></li><li>approval-adjacent interaction records</li></ul><p>This table backs the run Conversation view.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><code>PolicyDecision</code> is an owned type on <code>workflow_run_steps</code>.</li><li><code>approval_requests</code>, <code>agent_interactions</code>, and <code>workflow_run_context</code> are standalone tables keyed by run id in the current model.</li><li>Approvals still live in <code>approval_requests</code>; folding them into <code>agent_interactions</code> is a possible future consolidation.</li></ul><h2 id="migration-commands" tabindex="-1">Migration commands <a class="header-anchor" href="#migration-commands" aria-label="Permalink to &quot;Migration commands&quot;">​</a></h2><p>Add a migration:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrations</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Autofac.Infrastructure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --startup-project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Autofac.Api</span></span></code></pre></div><p>List migrations:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrations</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Autofac.Infrastructure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --startup-project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Autofac.Api</span></span></code></pre></div><p>Generate an idempotent SQL script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrations</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --idempotent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Autofac.Infrastructure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --startup-project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Autofac.Api</span></span></code></pre></div>',37)])])}const u=s(o,[["render",l]]);export{k as __pageData,u as default};
